def build_tree_from_preorder_inorder(preorder: List[int], inorder: List[int]) -> List[Optional[int]]:
    inorder_map = {val: i for i, val in enumerate(inorder)}
    pre_idx = [0]

    def build(left, right):
        if left > right:
            return None
        root_val = preorder[pre_idx[0]]
        pre_idx[0] += 1
        root = TreeNode(root_val)
        mid = inorder_map[root_val]
        root.left = build(left, mid - 1)
        root.right = build(mid + 1, right)
        return root

    root = build(0, len(inorder) - 1)
    return tree_to_list(root)

from typing import List, Optional
from collections import deque

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def tree_to_list(root: Optional[TreeNode]) -> List[Optional[int]]:
    if not root:
        return []
    result = []
    queue = deque([root])
    while queue:
        node = queue.popleft()
        if node:
            result.append(node.val)
            queue.append(node.left)
            queue.append(node.right)
        else:
            result.append(None)
    while result and result[-1] is None:
        result.pop()
    return result

def build_tree_from_preorder_inorder(preorder: List[int], inorder: List[int]) -> List[Optional[int]]:
    def build(pre, ino):
        if not pre or not ino:
            return None
        root_val = pre[0]
        root = TreeNode(root_val)
        mid = ino.index(root_val)
        root.left = build(pre[1:mid + 1], ino[:mid])
        root.right = build(pre[mid + 1:], ino[mid + 1:])
        return root

    root = build(preorder, inorder)
    return tree_to_list(root)

class TreeNode {
  constructor(val = 0, left = null, right = null) { this.val = val; this.left = left; this.right = right; }
}
function treeToList(root) {
  if (!root) return [];
  const result = []; const queue = [root];
  while (queue.length > 0) {
    const node = queue.shift();
    if (node) { result.push(node.val); queue.push(node.left); queue.push(node.right); }
    else result.push(null);
  }
  while (result.length > 0 && result[result.length - 1] === null) result.pop();
  return result;
}
function buildTreeFromPreorderInorder(preorder, inorder) {
  const inorderMap = new Map();
  inorder.forEach((val, i) => inorderMap.set(val, i));
  let preIdx = 0;
  function build(left, right) {
    if (left > right) return null;
    const rootVal = preorder[preIdx++];
    const root = new TreeNode(rootVal);
    const mid = inorderMap.get(rootVal);
    root.left = build(left, mid - 1);
    root.right = build(mid + 1, right);
    return root;
  }
  return treeToList(build(0, inorder.length - 1));
}
